export interface BannerInput {
    appName: string;
    type?: 'INFO' | 'WARNING' | 'ERROR';
    content?: string;
}
export interface Banner extends BannerInput {
    lastUpdatedBy: string;
    lastUpdatedOn: number;
}
export interface HarmonyApiBanners {
    /**
     * Fetches the banner for a particular app.
     *
     * @param {String} appName (required) to fetch the banner for.
     * @memberof window.harmony.api.banners
     * @async
     */
    get: ({ appName }: {
        appName: string;
    }) => Promise<Banner>;
    /**
     * Updates/Creates a Banner for your App. Harmony App Resource Type must already be created through HarmonyCLI to do permission check on.
     * The user must have 'Can edit banners' permission on the Harmony App Resource in Bindles.
     *
     * @param {String} appName (required) to create the banner for.
     * @param {String} type of the banner. Allowed valeus are 'INFO', 'WARNING', 'ERROR'. Defaults to 'INFO' type.
     * @param {String} content. Content of the banner. Pass empty banner content to takedown the current banner.
     * @memberof window.harmony.api.banners
     * @async
     */
    update: (bannerInput: BannerInput) => Promise<Banner>;
}
